// Try to cast `that` to a float64, or return an error.
func int64ToJsonable(
	that int64,
) (result float64, err error) {
	if that > 9007199254740991 || that < -9007199254740991 {
		err = newSerializationError(
			fmt.Sprintf(
				"64-bit integer can not be represented as 64-bit float in JSON: %v",
				that,
			),
		)
		return
	}

	result = float64(that);
	return
}

// Encode `bytes` to a base64 string.
func bytesToJsonable(
	bytes []byte,
) (result string, err error) {
	if bytes == nil {
		err = newSerializationError(
			"Expected an array of bytes, but got nil",
		)
		return
	}

	result = b64.StdEncoding.EncodeToString(
		bytes,
	)
	return
}

// Serialize [aastypes.ISomeItem] as a JSON-able map.
//
// This function performs no dispatch! It is only used to serialize
// the properties. If you want to serialize an instance of
// [aastypes.ISomeItem] with proper dispatch, call
// [ToJsonable].
func someItemToMap(
	that aastypes.ISomeItem,
) (result map[string]interface{}, err error) {
	result = make(map[string]interface{})

	result["name"] = that.Name()

	result["modelType"] = "SomeItem"

	return
}

// Serialize [aastypes.IAnotherItem] as a JSON-able map.
//
// This function performs no dispatch! It is only used to serialize
// the properties. If you want to serialize an instance of
// [aastypes.IAnotherItem] with proper dispatch, call
// [ToJsonable].
func anotherItemToMap(
	that aastypes.IAnotherItem,
) (result map[string]interface{}, err error) {
	result = make(map[string]interface{})

	var jsonableSerialNumber interface{}
	jsonableSerialNumber, err = int64ToJsonable(
		that.SerialNumber(),
	)
	if err != nil {
		if seriaErr, ok := err.(*SerializationError); ok {
			seriaErr.Path.PrependName(
				&aasreporting.NameSegment{
					Name: "SerialNumber()",
				},
			)
		}

		return
	}
	result["serialNumber"] = jsonableSerialNumber

	result["modelType"] = "AnotherItem"

	return
}

